import React from 'react';
import { Line } from 'react-chartjs-2';

function Chart(props){
    const dates = props.tradeList.filter(item => {
        return item.id
    })
    const months = dates.id
    const profits = props.tradeList.filter(item => {
        return item.profitLoss
    })
    console.log('months')
    console.log(months)
    console.log('profits')
    console.log(profits)

    return(
        <div>
            <Line
                data={{
                    labels:[{months}],
                    datasets:[{
                        label:'Profits',
                        data:{profits},
                        fill:false,
                        borderColor:'rgb(75, 192, 192)',
                        tension:0.1
                    }]
                }}
                height='10' width='10' />
        </div>
    )
}

export default Chart;
